mapper.insert:
/** UsptRsltDao.insert */
insert into uspt_rslt
	(
		rslt_id
		, apply_id
		, rslt_sttus_cd
		, presentn_dt
		, makeup_req_de
		, makeup_req_cn
		, makeup_attachment_group_id
		, attachment_group_id
		, sndng_mth
		, sndng_cn
		, recent_send_date
		, rslt_ym
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{rsltId}
		, #{applyId}
		, #{rsltSttusCd}
		, #{presentnDt}
		, #{makeupReqDe}
		, #{makeupReqCn}
		, #{makeupAttachmentGroupId}
		, #{attachmentGroupId}
		, #{sndngMth}
		, #{sndngCn}
		, #{recentSendDate}
		, #{rsltYm}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptRsltDao.update */
update uspt_rslt
set
	rslt_sttus_cd			= #{rsltSttusCd}
	, presentn_dt			= #{presentnDt}
	, attachment_group_id	= #{attachmentGroupId}
	, updater_id			= #{updaterId}
	, updated_dt			= #{updatedDt}
	, makeup_req_de			= #{makeupReqDe}
	, makeup_req_cn			= #{makeupReqCn}
	, makeup_attachment_group_id = #{makeupAttachmentGroupId}
where
	rslt_id = #{rsltId}

sql.where:
ulst.slctn = true

	and ub.bsns_year = #{bsnsYear}


	and ur.rslt_sttus_cd = #{rsltSttusCd}




			and ubpa.receipt_no like concat('%', #{keyword}, '%')


			and ubpat.task_nm_ko like concat('%', #{keyword}, '%')


			and ub.bsns_nm like concat('%', #{keyword}, '%')


			and cm.member_nm like concat('%', #{keyword}, '%')




	and ulst.apply_id in

		#{item}



	and ur.rslt_id is null

mapper.select:
/** UsptRsltDao.selectListCount */ select count(ulst.apply_id) from uspt_last_slctn_trget ulst inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = ulst.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join cmmt_member cm on cm.member_id = ubpa.member_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id and ubp.enabled = true inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd and ub.enabled = true inner join uspt_stdr_bsns usb on usb.stdr_bsns_cd = ub.stdr_bsns_cd and usb.bsns_type_cd != '${@aicluster.pms.common.util.Code@BSNS_TYPE_MVN_CODE}' inner join uspt_bsns_job_step ubjs on ubjs.bsns_cd = ub.bsns_cd and ubjs.job_step_cd = '${@aicluster.pms.common.util.Code@JOBSTEP_RSLT}' inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId}
and ubc.charger_author_cd = 'WRITE'
left outer join uspt_rslt ur on ur.apply_id = ulst.apply_id

/** UsptRsltDao.selectList */ select ulst.apply_id , ur.rslt_id , ub.bsns_year , ub.bsns_nm , ubpa.receipt_no , ubpat.task_nm_ko as task_nm , cm.member_nm , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@RSLT_CODE_GROUP}', ur.rslt_sttus_cd) as rslt_sttus , ur.presentn_dt , ubc.charger_author_cd , row_number() over (order by ulst.created_dt desc) as rn , cm.member_id , cm.enc_email , cm.enc_mobile_no from uspt_last_slctn_trget ulst inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = ulst.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join cmmt_member cm on cm.member_id = ubpa.member_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id and ubp.enabled = true inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd and ub.enabled = true inner join uspt_stdr_bsns usb on usb.stdr_bsns_cd = ub.stdr_bsns_cd and usb.bsns_type_cd != '${@aicluster.pms.common.util.Code@BSNS_TYPE_MVN_CODE}' inner join uspt_bsns_job_step ubjs on ubjs.bsns_cd = ub.bsns_cd and ubjs.job_step_cd = '${@aicluster.pms.common.util.Code@JOBSTEP_RSLT}' inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId}
and ubc.charger_author_cd = 'WRITE'
left outer join uspt_rslt ur on ur.apply_id = ulst.apply_id

sql.where:
ubpa.member_id = #{memberId}

	and ub.bsns_year = #{bsnsYear}


	and ur.rslt_sttus_cd = #{rsltSttusCd}




			and ubpa.receipt_no like concat('%', #{keyword}, '%')


			and ubpat.task_nm_ko like concat('%', #{keyword}, '%')


			and ubp.pblanc_nm like concat('%', #{keyword}, '%')

mapper.select:
/** UsptRsltDao.selectStatsList */ select sub.member_nm , array_to_string(array_agg(sub.iem_unit_cd), '@@@') as iem_unit_cd , array_to_string(array_agg(sub.rslt_iem_nm), '@@@') as rslt_iem_nm , array_to_string(array_agg(sub.rslt_idx_iem_cn), '@@@') as rslt_idx_iem_cn from ( select cm.member_nm , case when ubri.std_idx = true then ubrisi.iem_unit_cd else ubridi.iem_unit_cd end as iem_unit_cd , concat(ubri.rslt_idx_nm, ' ', ubridi.detail_iem_nm, case when ubri.std_idx = true then concat(' ', ubrisi.std_iem_nm) end) as rslt_iem_nm , uriic.rslt_idx_iem_cn from uspt_rslt ur inner join uspt_rslt_idx_iem urii on urii.rslt_id = ur.rslt_id inner join uspt_bsns_rslt_idx ubri on ubri.rslt_idx_id = urii.rslt_idx_id inner join uspt_rslt_idx_iem_cn uriic on uriic.rslt_idx_iem_id = urii.rslt_idx_iem_id and trim(uriic.rslt_idx_iem_cn) != '' inner join uspt_bsns_rslt_idx_detail_iem ubridi on ubridi.rslt_idx_detail_iem_id = uriic.rslt_idx_detail_iem_id and ubridi.iem_unit_cd not in ('TEXT', 'DSCRP', 'PT') left outer join uspt_bsns_rslt_idx_std_iem ubrisi on ubrisi.rslt_idx_std_iem_id = uriic.rslt_idx_std_iem_id and ubrisi.iem_unit_cd not in ('TEXT', 'DSCRP', 'PT') inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = ur.apply_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id inner join uspt_bsns ub on ubp.bsns_cd = ub.bsns_cd inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} inner join cmmt_member cm on cm.member_id = ubpa.member_id where ur.rslt_sttus_cd = '${@aicluster.pms.common.util.Code@RSLT_STTUS_RC_CODE}' and ub.bsns_year = #{bsnsYear} and ub.bsns_cd = #{bsnsCd}
and ubp.bsns_bgnde >= #{bsnsBgnde}
and ubp.bsns_endde <= #{bsnsEndde}
and cm.member_nm like concat('%', #{memberNm}, '%')
) sub group by sub.member_nm
